          </div>

          {/* Social Login Section */}
          <div className="space-y-4">
            {errorMsg && (
              <div className="p-3 bg-red-500/10 border border-red-500/20 rounded-xl flex items-center gap-3 text-red-500 animate-in fade-in slide-in-from-top-2">
                <AlertCircle size={18} />
                <span className="text-xs font-bold">{errorMsg}</span>
              </div>
            )}

            <button 
              onClick={handleGoogleLogin}
              disabled={isLoading}
              className="w-full h-16 bg-white text-slate-900 rounded-[1.8rem] font-bold text-sm flex items-center justify-center gap-3 transition-all hover:bg-slate-100 active:scale-[0.98] disabled:opacity-70 disabled:scale-100"
            >
              {isLoading ? (
                <Loader2 className="animate-spin text-slate-900" size={20} />
              ) : (
                <>
                  <svg className="w-5 h-5" viewBox="0 0 24 24">
                    <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
                    <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
                    <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/>
                    <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
                  </svg>
                  <span>Continuar com Google</span>
                </>
              )}
            </button>

            <div className="relative flex py-2 items-center">
                <div className="flex-grow border-t border-white/10"></div>
                <span className="flex-shrink mx-4 text-[9px] font-black text-slate-600 uppercase tracking-[0.2em] italic">Ou via Credencial</span>
                <div className="flex-grow border-t border-white/10"></div>
            </div>
          </div>

          <div className="space-y-5">
             <InputField icon={<User size={18}/>} label="Identidade (Nome)" placeholder="Como quer ser chamado?" />
             <InputField icon={<Mail size={18}/>} label="E-mail Operacional" placeholder="seu@email.com" />
             <InputField icon={<Lock size={18}/>} label="Chave de Acesso" placeholder="Mínimo 8 caracteres" showPass />
          </div>

          <button 
            onClick={handleCreate}
            disabled={isLoading}
            className="w-full h-20 bg-white/5 border border-white/10 hover:bg-primary hover:text-black hover:border-primary text-white rounded-[2rem] font-black uppercase text-sm flex items-center justify-center gap-3 transition-all active:scale-[0.98] mt-6 group disabled:opacity-50 disabled:hover:bg-white/5 disabled:hover:text-white"
          >
            {isLoading ? (
               <Loader2 className="animate-spin" />
            ) : (
               <>
                 CRIAR CONTA MANUAL <ChevronRight size={18} className="group-hover:translate-x-1 transition-transform" />
               </>
            )}
          </button>
        </div>
      </main>
    </div>
  );
};

const InputField = ({ icon, label, placeholder, showPass }: any) => (
  <div className="space-y-2">
    <label className="text-[9px] font-black uppercase text-slate-500 ml-4 italic tracking-[0.2em]">{label}</label>
    <div className="relative group">
      <div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-600 group-focus-within:text-primary transition-colors">
        {icon}
      </div>
      <input 
        type={showPass ? "password" : "text"}
        placeholder={placeholder}
        className="w-full h-16 bg-white/[0.02] border border-white/5 rounded-[1.5rem] pl-14 pr-12 text-sm focus:border-primary/40 focus:bg-white/[0.04] outline-none transition-all placeholder:text-slate-700 font-medium text-white"
      />
      {showPass && (
        <button className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-700 hover:text-slate-400 transition-colors">
          <EyeOff size={18} />
        </button>
      )}
    </div>
  </div>
);

export default Login;
